#!/usr/bin/env bash
set -Eeuo pipefail

VERSION="1.10.0"
APP_ROOT="/opt/veloraos"
SERVICE="veloraos"
SERVICE_FILE="/etc/systemd/system/veloraos.service"
UPDATE_SERVICE_FILE="/etc/systemd/system/veloraos-update.service"
RUNNER_FILE="/usr/local/sbin/veloraos-update-runner"
PORT="8099"
TEST_PORT="18200"
STAMP="$(date +%Y%m%d-%H%M%S)"
STAGE="/opt/.veloraos-update-stage-${VERSION}-${STAMP}"
ROLLBACK="/opt/.veloraos-update-rollback-${VERSION}-${STAMP}"
BACKUP="/opt/veloraos-update-backups/pre-${VERSION}-${STAMP}"
PAYLOAD_DIR="$(mktemp -d /tmp/veloraos-update-payload.XXXXXX)"
PAYLOAD_ARCHIVE="$PAYLOAD_DIR/payload.tar.gz"
PAYLOAD_SHA256="41b20b9975439784e02b8ebb0971e232d926c92292c7b42c13b274c28e84e178"
TEST_PID=""
DEPLOY_STARTED=0
SUCCESS=0
NON_INTERACTIVE=0

log(){ printf '[VeloraOS update %s] %s\n' "$VERSION" "$*"; }
die(){ printf '[Error] %s\n' "$*" >&2; exit 1; }
cleanup(){
  if [[ -n "$TEST_PID" ]] && kill -0 "$TEST_PID" 2>/dev/null; then
    kill "$TEST_PID" 2>/dev/null || true
    wait "$TEST_PID" 2>/dev/null || true
  fi
  rm -rf "$PAYLOAD_DIR" "$STAGE" 2>/dev/null || true
}
rollback(){
  local code=$?
  trap - EXIT INT TERM
  if [[ "$SUCCESS" == "1" ]]; then cleanup; exit 0; fi
  if [[ "$DEPLOY_STARTED" == "1" ]]; then
    log 'Update failed after deployment began; restoring the previous installation.'
    systemctl stop "$SERVICE" 2>/dev/null || true
    [[ -d "$APP_ROOT" ]] && rm -rf "$APP_ROOT"
    [[ -d "$ROLLBACK" ]] && mv "$ROLLBACK" "$APP_ROOT"
    [[ -f "$BACKUP/veloraos.service" ]] && cp -a "$BACKUP/veloraos.service" "$SERVICE_FILE"
    if [[ -f "$BACKUP/veloraos-update.service" ]]; then cp -a "$BACKUP/veloraos-update.service" "$UPDATE_SERVICE_FILE"; else rm -f "$UPDATE_SERVICE_FILE"; fi
    if [[ -f "$BACKUP/veloraos-update-runner" ]]; then cp -a "$BACKUP/veloraos-update-runner" "$RUNNER_FILE"; else rm -f "$RUNNER_FILE"; fi
    systemctl daemon-reload 2>/dev/null || true
    systemctl restart "$SERVICE" 2>/dev/null || true
  fi
  cleanup
  exit "$code"
}
trap rollback EXIT INT TERM

usage(){
  cat <<'USAGE'
Usage: sudo bash VeloraOS-Update-1.10.0-Image-Studio-V2.sh --non-interactive

This update is designed for the VeloraOS Web UI update service. It does not
prompt, modify the stored licence, replace the device identity, or remove user data.
USAGE
}

for arg in "$@"; do
  case "$arg" in
    --non-interactive) NON_INTERACTIVE=1 ;;
    -h|--help) usage; exit 0 ;;
    *) die "Unknown option: $arg" ;;
  esac
done
[[ "$NON_INTERACTIVE" == "1" || "${VELORAOS_NONINTERACTIVE:-0}" == "1" ]] || die 'This updater requires --non-interactive.'
[[ ${EUID:-$(id -u)} -eq 0 ]] || die 'This updater must run as root.'
[[ -d "$APP_ROOT" && -f "$APP_ROOT/app/main.py" && -x "$APP_ROOT/.venv/bin/python" ]] || die 'The installed VeloraOS layout is incomplete.'
for command in bash awk base64 tr tar python3 node curl openssl systemctl sha256sum; do command -v "$command" >/dev/null 2>&1 || die "Required command is missing: $command"; done
bash -n "$0" || die 'The update wrapper failed its own shell syntax check.'

mkdir -p "$BACKUP"
cp -a "$APP_ROOT" "$BACKUP/veloraos"
[[ -f "$SERVICE_FILE" ]] && cp -a "$SERVICE_FILE" "$BACKUP/veloraos.service"
[[ -f "$UPDATE_SERVICE_FILE" ]] && cp -a "$UPDATE_SERVICE_FILE" "$BACKUP/veloraos-update.service"
[[ -f "$RUNNER_FILE" ]] && cp -a "$RUNNER_FILE" "$BACKUP/veloraos-update-runner"

log 'Extracting the verified 1.10.0 payload.'
# Normalise transport-only whitespace (including CRLF) while keeping Base64
# decoding strict. The embedded archive checksum rejects truncation or edits.
awk '{line=$0; sub(/\r$/, "", line)} line=="__VELORA_PAYLOAD_BELOW__" {found=1; next} found {print} END {if (!found) exit 2}' "$0" \
  | tr -d '[:space:]' \
  | base64 --decode > "$PAYLOAD_ARCHIVE" \
  || die 'The embedded update payload is missing or is not valid Base64. Download the raw script again rather than copying it through an editor.'
ACTUAL_PAYLOAD_SHA256="$(sha256sum "$PAYLOAD_ARCHIVE" | awk '{print $1}')"
[[ "$ACTUAL_PAYLOAD_SHA256" == "$PAYLOAD_SHA256" ]] || die 'The embedded update payload checksum does not match; the script is truncated or modified.'
tar -tzf "$PAYLOAD_ARCHIVE" >/dev/null || die 'The embedded update payload is not a valid gzip archive.'
tar -xzf "$PAYLOAD_ARCHIVE" -C "$PAYLOAD_DIR"
[[ -f "$PAYLOAD_DIR/app/main.py" && -f "$PAYLOAD_DIR/app/updater.py" && -f "$PAYLOAD_DIR/veloraos-update.service" && -f "$PAYLOAD_DIR/bin/veloraos-update-runner" ]] || die 'The embedded update payload is incomplete.'

rm -rf "$STAGE"
mkdir -p "$STAGE/app/static" "$STAGE/data" "$STAGE/bin"
cp -a "$PAYLOAD_DIR/app/." "$STAGE/app/"
cp -a "$PAYLOAD_DIR/bin/." "$STAGE/bin/"
cp -a "$PAYLOAD_DIR/requirements.txt" "$STAGE/requirements.txt"
cp -a "$PAYLOAD_DIR/veloraos.service" "$STAGE/veloraos.service"
cp -a "$PAYLOAD_DIR/veloraos-update.service" "$STAGE/veloraos-update.service"
cp -a "$APP_ROOT/data/." "$STAGE/data/"
cp -a "$APP_ROOT/.venv" "$STAGE/.venv"
[[ -f "$APP_ROOT/VERSION" ]] && cp -a "$APP_ROOT/VERSION" "$STAGE/VERSION"

# Preserve current app icon definitions and additional local artwork. Licensing
# secrets and the stable device identity live outside /opt/veloraos and are not touched.
if [[ -f "$APP_ROOT/app/static/app.js" ]]; then
  python3 - "$APP_ROOT/app/static/app.js" "$STAGE/app/static/app.js" <<'PY_ICONS'
import re, sys
from pathlib import Path
old_path, new_path = map(Path, sys.argv[1:3])
old = old_path.read_text(encoding="utf-8", errors="replace")
new = new_path.read_text(encoding="utf-8", errors="replace")
pattern = re.compile(r"var icons=\{.*?\n\};\n\n(?=var S=)", re.S)
old_match = pattern.search(old)
new_match = pattern.search(new)
if old_match and new_match:
    new = new[:new_match.start()] + old_match.group(0) + new[new_match.end():]
    new_path.write_text(new, encoding="utf-8")
PY_ICONS
  cp "$STAGE/app/static/app.js" "$STAGE/app/static/app-11000.js"
fi
find "$APP_ROOT/app/static" -maxdepth 1 -type f \( -iname '*.png' -o -iname '*.jpg' -o -iname '*.jpeg' -o -iname '*.webp' -o -iname '*.gif' -o -iname '*.svg' -o -iname '*.ico' \) -print0 | while IFS= read -r -d '' artwork; do
  target="$STAGE/app/static/$(basename "$artwork")"
  [[ -e "$target" ]] || cp -a "$artwork" "$target"
done

cp "$STAGE/app/static/app.js" "$STAGE/app/static/app-11000.js"
cp "$STAGE/app/static/style.css" "$STAGE/app/static/style-11000.css"
sed -i -E 's#style-[0-9]+\.css(\?v=[0-9]+)?#style-11000.css#g;s#app-[0-9]+\.js(\?v=[0-9]+)?#app-11000.js#g' "$STAGE/app/static/index.html"

if ! "$STAGE/.venv/bin/python" -c 'import packaging' >/dev/null 2>&1; then
  "$STAGE/.venv/bin/python" -m pip install 'packaging==25.0'
fi

chmod 755 "$STAGE" "$STAGE/app" "$STAGE/app/static" "$STAGE/data" "$STAGE/bin"
chmod 644 "$STAGE/app/"*.py "$STAGE/app/static/"* "$STAGE/requirements.txt" "$STAGE/veloraos.service" "$STAGE/veloraos-update.service"
chmod 755 "$STAGE/bin/"*

log 'Running syntax and staged-server checks.'
"$STAGE/.venv/bin/python" -m py_compile "$STAGE/app/main.py" "$STAGE/app/image_studio.py" "$STAGE/app/licensing.py" "$STAGE/app/license_cli.py" "$STAGE/app/updater.py" "$STAGE/app/backup_recovery.py" "$STAGE/bin/veloraos-update-runner"
node --check "$STAGE/app/static/app-11000.js"
grep -Fq 'VERSION = "1.10.0"' "$STAGE/app/main.py" || die 'The update version marker is missing.'
grep -Fq '/api/update/status' "$STAGE/app/main.py" || die 'The update API is missing.'
grep -Fq 'System updates' "$STAGE/app/static/app-11000.js" || die 'The update interface is missing.'
grep -Fq 'allModels(includeUninstalled)' "$STAGE/app/static/app-11000.js" || die 'Installed-only chat model selection is missing.'
grep -Fq '.top .brand>div:not(.logo){display:none}' "$STAGE/app/static/style-11000.css" || die 'Header logo visibility fix is missing.'
grep -Fq 'toggleMobileChats' "$STAGE/app/static/app-11000.js" || die 'Mobile chat drawer behaviour is missing.'
grep -Fq 'mobile app-style layout' "$STAGE/app/static/style-11000.css" || die 'Mobile responsive layout is missing.'
grep -Fq 'viewport-fit=cover' "$STAGE/app/static/index.html" || die 'Mobile safe-area viewport support is missing.'
grep -Fq 'accessibilityChrome' "$STAGE/app/static/app-11000.js" || die 'Accessibility landmarks and live regions are missing.'
grep -Fq 'role="log"' "$STAGE/app/static/app-11000.js" || die 'Accessible chat log semantics are missing.'
grep -Fq 'accessibility closeout' "$STAGE/app/static/style-11000.css" || die 'Accessibility styling is missing.'
grep -Fq 'forced-colors:active' "$STAGE/app/static/style-11000.css" || die 'Forced-colour support is missing.'
test -f "$STAGE/app/image_studio.py" || die 'The Image Studio backend is missing.'
grep -Fq '@app.post("/api/image-studio/generate")' "$STAGE/app/main.py" || die 'The Image Studio generation API is missing.'
grep -Fq 'CheckpointLoaderSimple' "$STAGE/app/image_studio.py" || die 'The ComfyUI workflow is missing.'
grep -Fq 'require_csrf(request)' "$STAGE/app/main.py" || die 'CSRF protection is missing.'
grep -Fq 'function imageStudioPage()' "$STAGE/app/static/app-11000.js" || die 'The Image Studio workspace is missing.'
grep -Fq 'Image Studio V2' "$STAGE/app/static/style-11000.css" || die 'The Image Studio styling is missing.'
test -f "$STAGE/app/static/logo-mark.svg" || die 'VeloraOS wordmark is missing.'
grep -Fq 'device_mismatch' "$STAGE/app/licensing.py" || die 'Licensing error-state polish is missing.'
grep -Fq '/api/setup/status' "$STAGE/app/main.py" || die 'The first-run setup API is missing.'
grep -Fq 'password_change_required' "$STAGE/app/main.py" || die 'The first-run password gate is missing.'
grep -Fq 'First-run setup' "$STAGE/app/static/app-11000.js" || die 'The first-run setup interface is missing.'
grep -Fq 'Default password: veloraos' "$STAGE/app/static/app-11000.js" || die 'The default-password guidance is missing.'
grep -Fq 'id="setup-continue"' "$STAGE/app/static/app-11000.js" || die 'The setup Continue control is missing.'
grep -Fq 'function finishSetupTransition(step){S.setupBusy=false' "$STAGE/app/static/app-11000.js" || die 'The setup navigation state fix is missing.'
grep -Fq '/api/diagnostics' "$STAGE/app/main.py" || die 'The diagnostics API is missing.'
grep -Fq '/api/diagnostics/acceleration-test' "$STAGE/app/main.py" || die 'The acceleration-test API is missing.'
grep -Fq 'GPU & Ollama Diagnostics' "$STAGE/app/static/app-11000.js" || die 'The diagnostics interface is missing.'
grep -Fq 'Run acceleration test' "$STAGE/app/static/app-11000.js" || die 'The acceleration-test control is missing.'
grep -Fq 'Edit & resend' "$STAGE/app/static/app-11000.js" || die 'The edit-and-resend control is missing.'
grep -Fq 'Regenerate' "$STAGE/app/static/app-11000.js" || die 'The regenerate control is missing.'
grep -Fq 'Export Markdown' "$STAGE/app/static/app-11000.js" || die 'The Markdown export control is missing.'
grep -Fq 'Search titles and messages' "$STAGE/app/static/app-11000.js" || die 'The chat search control is missing.'
grep -Fq '/api/backups' "$STAGE/app/main.py" || die 'The backup and restore API is missing.'
grep -Fq 'Secure restoration' "$STAGE/app/static/app-11000.js" || die 'The backup and restore interface is missing.'
grep -Fq '/api/recovery/repair-permissions' "$STAGE/app/main.py" || die 'The recovery tools API is missing.'
grep -Fq 'Sanitised diagnostics ZIP' "$STAGE/app/static/app-11000.js" || die 'The recovery and support interface is missing.'
grep -Fq 'nav nav-dock' "$STAGE/app/static/app-11000.js" || die 'The dock header interface is missing.'
grep -Fq -- '-webkit-appearance:none' "$STAGE/app/static/style-11000.css" || die 'The profile menu theme reset is missing.'
grep -Fq 'profile menu layer and clipping fix' "$STAGE/app/static/style-11000.css" || die 'The profile menu layer fix is missing.'
grep -Fq 'ExecStart=/usr/local/sbin/veloraos-update-runner' "$STAGE/veloraos-update.service" || die 'The update service is invalid.'
(
  cd "$STAGE"
  exec env VELORAOS_ROOT="$STAGE" VELORAOS_LICENSE_DIR="$STAGE/test-etc" VELORAOS_STATE_DIR="$STAGE/test-state" VELORAOS_UPDATE_START_DELAY=9999 "$STAGE/.venv/bin/python" -m uvicorn app.main:app --host 127.0.0.1 --port "$TEST_PORT"
) > "$STAGE/test-server.log" 2>&1 &
TEST_PID=$!
for _ in $(seq 1 40); do curl -fsS "http://127.0.0.1:$TEST_PORT/api/health" >/dev/null 2>&1 && break; sleep 1; done
curl -fsS "http://127.0.0.1:$TEST_PORT/api/health" | grep -Fq '"version":"1.10.0"' || { cat "$STAGE/test-server.log" >&2; die 'The staged Web UI health check failed.'; }
kill "$TEST_PID" 2>/dev/null || true
wait "$TEST_PID" 2>/dev/null || true
TEST_PID=""

log 'Deploying atomically.'
systemctl stop "$SERVICE"
DEPLOY_STARTED=1
rm -rf "$ROLLBACK"
mv "$APP_ROOT" "$ROLLBACK"
mv "$STAGE" "$APP_ROOT"
install -m 0644 "$APP_ROOT/veloraos.service" "$SERVICE_FILE"
install -m 0644 "$APP_ROOT/veloraos-update.service" "$UPDATE_SERVICE_FILE"
install -m 0755 "$APP_ROOT/bin/veloraos-update-runner" "$RUNNER_FILE"
systemctl daemon-reload
systemctl enable "$SERVICE" >/dev/null
systemctl start "$SERVICE"
for _ in $(seq 1 45); do curl -fsS "http://127.0.0.1:$PORT/api/health" >/dev/null 2>&1 && break; sleep 1; done
curl -fsS "http://127.0.0.1:$PORT/api/health" | grep -Fq '"version":"1.10.0"' || die 'The updated Web UI health check failed.'

# Record the release only after the deployed service passes its live health check.
VERSION_TMP="$APP_ROOT/.VERSION.${STAMP}.tmp"
printf '%s\n' "$VERSION" > "$VERSION_TMP"
chmod 0644 "$VERSION_TMP"
mv -f "$VERSION_TMP" "$APP_ROOT/VERSION"

SUCCESS=1
trap - EXIT INT TERM
cleanup
log 'VeloraOS 1.10.0 installed successfully.'
exit 0
